1011 |     function todayKey() {
1012 |       const d = new Date();
1013 |       return `${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,'0')}-${String(d.getDate()).padStart(2,'0')}`;
1014 |     }
1015 | 
1016 |     function isWeekend(dateKey) {
1017 |       // dateKey is "YYYY-MM-DD"; Date constructor treats this as UTC midnight,
1018 |       // so add 'T12:00' to keep it in local timezone.
1019 |       const d = new Date(dateKey + 'T12:00:00');
1020 |       return d.getDay() === 0 || d.getDay() === 6; // 0=Sun, 6=Sat
1021 |     }
1022 | 
1023 |     function prevWeekday(dateKey) {
1024 |       const d = new Date(dateKey + 'T12:00:00');
1025 |       do { d.setDate(d.getDate() - 1); } while (d.getDay() === 0 || d.getDay() === 6);
1026 |       return `${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,'0')}-${String(d.getDate()).padStart(2,'0')}`;
1027 |     }
