1029 |     function checkStreakExpiry() {
1030 |       // Run on boot. If today is a weekday and the last active weekday wasn't
1031 |       // the immediately preceding weekday, the streak is broken → reset to 0.
1032 |       if (!state.lastStreakDate) return;     // never started, nothing to reset
1033 |       const today = todayKey();
1034 |       if (isWeekend(today)) return;          // weekend — grace period, no reset
1035 |       if (state.lastStreakDate === today) return; // already active today, fine
1036 |       // If the previous weekday wasn't the last active date, streak is broken.
1037 |       if (prevWeekday(today) !== state.lastStreakDate) {
