    if (bobWindow && !bobWindow.isDestroyed()) bobWindow.setPosition(x, y);
  });

  createMainWindow();
  createBobWindow();
  app.on('activate', () => { if (BrowserWindow.getAllWindows().length === 0) createMainWindow(); });
});
